const attendeesGmails = $input.first().json.Attendees_Gmails || "";
const emails = attendeesGmails.split(',').map(e => e.trim()).filter(e => e.length > 0);
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const invalidEmails = emails.filter(e => !emailRegex.test(e));

return {
  totalEmailsCount: emails.length,
  validEmailsCount: emails.length - invalidEmails.length,
  emails: emails,
  invalidEmails: invalidEmails
};

const durationText = $('On form submission').item.json.Duration || "30 min";
let durationInMinutes = 30;

if (durationText.includes('min')) {
  durationInMinutes = parseInt(durationText);
} else if (durationText.includes('hr')) {
  const hours = parseFloat(durationText);
  durationInMinutes = hours * 60;
}

return {
  durationInMinutes: durationInMinutes
};

const now = new Date();
const pastMeetings = [];

for (const item of $input.all()) {
  const status = item.Status;

  if (status === 'Scheduled' || status === 'Reminded') {

    const meetingStart = new Date(item["Date/Time"]);
    const durationMins = parseInt(item["Duration(mins)"]) || 0;

    const meetingEnd = new Date(meetingStart.getTime() + durationMins * 60000);


    if (meetingEnd < now) {
      pastMeetings.push({ json: item });
    }
  }
}

return pastMeetings;

const now = new Date();
const currentDay = now.getDay(); 
const startOfWeek = new Date(now);
const diffToMonday = currentDay === 0 ? -6 : 1 - currentDay; 
startOfWeek.setDate(now.getDate() + diffToMonday);
startOfWeek.setHours(0, 0, 0, 0);
const endOfWeek = new Date(startOfWeek);
endOfWeek.setDate(startOfWeek.getDate() + 6);
endOfWeek.setHours(23, 59, 59, 999);

let tableRows = '';
let hasMeetings = false;

for (const item of $input.all()) {
  const meeting = item.json;
  if (!meeting["Date/Time"]) continue;

  const meetingDate = new Date(meeting["Date/Time"]);


  if (meetingDate >= startOfWeek && meetingDate <= endOfWeek) {
    hasMeetings = true;


    const formattedDate = meetingDate.toLocaleString('en-US', { 
      timeZone: 'Asia/Karachi',
      dateStyle: 'medium', 
      timeStyle: 'short' 
    });


    tableRows += `
      <tr>
        <td style="border: 1px solid #dddddd; padding: 8px;">${meeting.Title || '-'}</td>
        <td style="border: 1px solid #dddddd; padding: 8px;">${formattedDate}</td>
        <td style="border: 1px solid #dddddd; padding: 8px;">${meeting.Attendees || '-'}</td>
        <td style="border: 1px solid #dddddd; padding: 8px;">${meeting.Status || '-'}</td>
        <td style="border: 1px solid #dddddd; padding: 8px;">${meeting.Gist || '-'}</td>
      </tr>
    `;
  }
}

let htmlBody = '';
if (hasMeetings) {
  htmlBody = `
    <h2 style="color: #2c3e50;">Weekly Meeting Digest</h2>
    <p>Here is the schedule for your meetings this week:</p>
    <table style="font-family: Arial, sans-serif; border-collapse: collapse; width: 100%;">
      <tr style="background-color: #f2f2f2; text-align: left;">
        <th style="border: 1px solid #dddddd; padding: 8px;">Title</th>
        <th style="border: 1px solid #dddddd; padding: 8px;">Date/Time</th>
        <th style="border: 1px solid #dddddd; padding: 8px;">Attendees</th>
        <th style="border: 1px solid #dddddd; padding: 8px;">Status</th>
        <th style="border: 1px solid #dddddd; padding: 8px;">Gist</th>
      </tr>
      ${tableRows}
    </table>
  `;
} else {
  htmlBody = `
    <h2 style="color: #2c3e50;">Weekly Meeting Digest</h2>
    <p style="font-family: Arial, sans-serif; font-size: 14px; color: #555;">No meetings scheduled for this week.</p>
  `;
}


return [{ json: { htmlEmail: htmlBody, digestDate: now.toLocaleDateString() } }];

const now = new Date();
const archiveThreshold = new Date();
// Aaj se strict 30 din purani date threshold set karna
archiveThreshold.setDate(now.getDate() - 30); 

const rowsToArchive = [];

for (const item of $input.all()) {
  const meeting = item.json;

  if (meeting && meeting["Status"]) {
    const statusValue = meeting["Status"].toString().trim();
    const dateValue = meeting["Date/Time"];

    // Check 1: Status exact 'Done' hona chahiye
    // Check 2: Date 30 din se purani honi chahiye
    if (statusValue === 'Done' && dateValue) {
      const meetingDate = new Date(dateValue);

      if (!isNaN(meetingDate) && meetingDate < archiveThreshold) {
        // Required ArchivedOn column add karna
        meeting.ArchivedOn = now.toISOString().replace('T', ' ').substring(0, 19); 
        rowsToArchive.push({ json: meeting });
      }
    }
  }
}

return rowsToArchive;

// Sirf aur sirf pichle node se aane wale fresh items ko real-time copy karna
const filteredItems = [];

for (const item of $input.all()) {
  filteredItems.push({ json: { ...item.json } });
}

// Rows ko real-time row_number ke mutabiq descending order (bade se chote) mein sort karna
filteredItems.sort((a, b) => {
  const rowA = parseInt(a.json.row_number) || 0;
  const rowB = parseInt(b.json.row_number) || 0;
  return rowB - rowA; 
});

return filteredItems;
